def fruit_distribution(s, n):
    # Extract numbers from the string
    # Split the string and look for numeric values
    words = s.split()
    apples = 0
    oranges = 0

    for i, word in enumerate(words):
        if word == "apples" and i > 0:
            # The number before "apples" should be the count
            try:
                apples = int(words[i-1])
            except ValueError:
                pass
        elif word == "oranges" and i > 0:
            # The number before "oranges" should be the count
            try:
                oranges = int(words[i-1])
            except ValueError:
                pass

    # Calculate mangoes: total fruits - apples - oranges
    return n - apples - oranges
