def valid_date(date):
    # Rule 1: The date string is not empty
    if not date:
        return False

    # Rule 4: Check format mm-dd-yyyy
    parts = date.split('-')
    if len(parts) != 3:
        return False

    mm, dd, yyyy = parts

    # Check if each part consists only of digits
    if not (mm.isdigit() and dd.isdigit() and yyyy.isdigit()):
        return False

    # Convert to integers
    try:
        month = int(mm)
        day = int(dd)
        year = int(yyyy)
    except ValueError:
        return False

    # Rule 3: Months should be between 1 and 12
    if month < 1 or month > 12:
        return False

    # Rule 2: Validate days based on month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        # Months with 31 days
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        # Months with 30 days
        if day < 1 or day > 30:
            return False
    elif month == 2:
        # February - up to 29 days (as specified in rule 2)
        if day < 1 or day > 29:
            return False

    # Additional check: ensure proper formatting (two digits for mm and dd, four digits for yyyy)
    # The problem doesn't explicitly require leading zeros, but the examples show them
    # Since the examples include '03-11-2000' and '06-04-2020', we should check for proper digit counts
    # However, the problem statement doesn't specify this as a requirement, so we'll focus on the given rules

    return True
```

