    if not date:
        return False

    # Rule 4: Check if the format is mm-dd-yyyy
    parts = date.split('-')
    if len(parts) != 3:
        return False

    month_str, day_str, year_str = parts

    # Check if all parts are numeric
    if not (month_str.isdigit() and day_str.isdigit() and year_str.isdigit()):
        return False

    # Convert to integers
    try:
        month = int(month_str)
        day = int(day_str)
        year = int(year_str)
    except ValueError:
        return False

    # Rule 3: Months should be between 1 and 12
    if month < 1 or month > 12:
        return False

    # Rule 2: Validate days based on month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        # 31 days
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        # 30 days
        if day < 1 or day > 30:
            return False
    elif month == 2:
        # 29 days (as specified in the problem, not checking leap years)
        if day < 1 or day > 29:
            return False

    # Additional check: ensure proper formatting (no leading zeros issues, but the examples show leading zeros are allowed)
    # Check that each part has the expected length: mm should be 2 chars, dd should be 2 chars, yyyy should be 4 chars
    if len(month_str) != 2 or len(day_str) != 2 or len(year_str) != 4:
        return False

    return True
