```python
def closest_integer(value):
    # Convert the string to a float
    num = float(value)

    # Get the integer part and fractional part
    int_part = int(num)
    frac_part = abs(num - int_part)

    # If the fractional part is exactly 0.5
    if frac_part == 0.5:
        # Round away from zero
        if num >= 0:
            return int_part + 1
        else:
            return int_part - 1
    else:
        # Use standard rounding for other cases
        # But we need to handle the "away from zero" requirement properly
        # For positive numbers: round half up, for negative: round half down
        if num >= 0:
            return int(num + 0.5)
        else:
            return int(num - 0.5)
```

```python
def is_sorted(lst):
    # Handle empty list or single element
    if len(lst) <= 1:
        return True

    # Check for duplicates: if any number appears more than twice, return False
    from collections import Counter
    counts = Counter(lst)
    if any(count > 2 for count in counts.values()):
        return False

    # Check if list is sorted in ascending order
    for i in range(1, len(lst)):
        if lst[i] < lst[i-1]:
            return False

    return True
```

