def is_sorted(lst):
    # Handle empty list or single element
    if len(lst) <= 1:
        return True

    # Check for duplicates: more than 1 duplicate of same number means >2 occurrences
    # Count occurrences of each number
    counts = {}
    for num in lst:
        counts[num] = counts.get(num, 0) + 1
        # If any number appears more than 2 times, return False immediately
        if counts[num] > 2:
            return False

    # Check if list is sorted in ascending order
    for i in range(1, len(lst)):
        if lst[i] < lst[i-1]:
            return False

    return True
