```python
def find_max(words):
    if not words:
        return None

    max_unique_count = -1
    candidates = []

    # Find the maximum number of unique characters
    for word in words:
        unique_count = len(set(word))
        if unique_count > max_unique_count:
            max_unique_count = unique_count
            candidates = [word]
        elif unique_count == max_unique_count:
            candidates.append(word)

    # Return the lexicographically smallest among candidates
    return min(candidates)
```

```python
def find_max(words):
    if not words:
        return None

    # Calculate unique character count for each word
    unique_counts = []
    for word in words:
        unique_count = len(set(word))
        unique_counts.append(unique_count)

    # Find the maximum number of unique characters
    max_unique_count = max(unique_counts)

    # Find all words with the maximum unique character count
    candidates = []
    for i, count in enumerate(unique_counts):
        if count == max_unique_count:
            candidates.append(words[i])

    # Return the lexicographically smallest among candidates
    return min(candidates)
```

