```python
def fib(n: int) -> int:
    if n <= 0:
        return 0
    elif n == 1:
        return 1
    else:
        a, b = 0, 1
        for _ in range(2, n + 1):
            a, b = b, a + b
        return b
```

```python
def solve(s):
    # Check if the string contains any letters
    has_letters = any(c.isalpha() for c in s)

    if not has_letters:
        # If no letters, reverse the string
        return s[::-1]
    else:
        # If has letters, reverse case of letters, keep others unchanged
        result = []
        for c in s:
            if c.isalpha():
                if c.islower():
                    result.append(c.upper())
                else:
                    result.append(c.lower())
            else:
                result.append(c)
        return ''.join(result)
```

