        # If there are letters, reverse the case of each letter
        result = ""
        for c in s:
            if c.isalpha():
                if c.islower():
                    result += c.upper()
                else:
                    result += c.lower()
            else:
                result += c
        return result
    else:
        # If no letters, reverse the entire string
        return s[::-1]
```

