def split_words(txt):
    # Check if there are whitespaces
    if ' ' in txt:
        return txt.split()

    # Check if there are commas
    elif ',' in txt:
        return txt.split(',')

    # Otherwise, count lowercase letters with odd order in alphabet
    # ord('a') = 97, but the problem states ord('a') = 0, so we need (ord(c) - ord('a'))
    # So 'a' -> 0, 'b' -> 1, ..., 'z' -> 25
    # We want letters where (ord(c) - ord('a')) % 2 == 1 (odd positions)
    count = 0
    for c in txt:
        if 'a' <= c <= 'z':
            position = ord(c) - ord('a')
            if position % 2 == 1:  # odd position (b=1, d=3, f=5, etc.)
                count += 1
    return count
```

