```python
def fix_spaces(text):
    result = ""
    i = 0
    while i < len(text):
        if text[i] != ' ':
            result += text[i]
            i += 1
        else:
            # Count consecutive spaces
            space_count = 0
            j = i
            while j < len(text) and text[j] == ' ':
                space_count += 1
                j += 1

            if space_count > 2:
                result += '-'
            else:
                result += '_' * space_count

            i = j

    return result
```

```python
def remove_vowels(text):
    vowels = "aeiouAEIOU"
    result = ""
    for char in text:
        if char not in vowels:
            result += char
    return result
```

